mapper.update:
/** CmmtMemberDayStatsDao.upsert */
insert into cmmt_member_day_stats (
	 stats_ymd
	,member_type
	,week_day_nm
	,total_mbr_cnt
	,join_mbr_cnt
	,secession_mbr_cnt
	,dormant_mbr_cnt
	,black_mbr_cnt
	,created_dt
) values

(
	 #{item.statsYmd}
	,#{item.memberType}
	,#{item.weekDayNm}
	,#{item.totalMbrCnt}
	,#{item.joinMbrCnt}
	,#{item.secessionMbrCnt}
	,#{item.dormantMbrCnt}
	,#{item.blackMbrCnt}
	,#{item.createdDt}
)

on conflict (stats_ymd, member_type)
do update set
	 week_day_nm       = excluded.week_day_nm
	,total_mbr_cnt     = excluded.total_mbr_cnt
	,join_mbr_cnt      = excluded.join_mbr_cnt
	,secession_mbr_cnt = excluded.secession_mbr_cnt
	,dormant_mbr_cnt   = excluded.dormant_mbr_cnt
	,black_mbr_cnt     = excluded.black_mbr_cnt
	,created_dt        = excluded.created_dt
